cards = []

# Major Arcana
for m in major:
    cards.append({
        "id": m[0], "name": m[1], "nameKo": m[2],
        "upright": m[3], "uprightKo": m[3],
        "reversed": m[4], "reversedKo": m[4],
        "description": m[5], "descriptionKo": m[5],
        "loveAdvice": m[6], "moneyAdvice": m[7],
        "healthAdvice": m[8], "workAdvice": m[9],
    })

# Minor Arcana
card_id = 22
for suit_en, data_list in minor_data.items():
    suit_ko = suits[suit_en]["ko"]
    adv = suit_advice[suit_en]
    for i, (rank_en, rank_ko, up, rev, desc) in enumerate(data_list):
        cards.append({
            "id": card_id,
            "name": f"{rank_en} of {suit_en}",
            "nameKo": f"{suit_ko} {rank_ko}",
            "upright": up, "uprightKo": up,
            "reversed": rev, "reversedKo": rev,
            "description": desc, "descriptionKo": desc,
            "loveAdvice": adv["love"][i],
            "moneyAdvice": adv["money"][i],
            "healthAdvice": adv["health"][i],
            "workAdvice": adv["work"][i],
        })
        card_id += 1

out = os.path.join(os.path.dirname(__file__), '..', 'assets', 'data', 'tarot_cards.json')
with open(out, 'w', encoding='utf-8') as f:
    json.dump(cards, f, ensure_ascii=False, indent=2)
print(f"Generated {len(cards)} cards -> {out}")
